// Create a store that:
// 1. Tracks current step
// 2. Stores form data
// 3. Provides navigation (next, prev, goTo)
// 4. Persists to localStorage
// 5. Has reset functionality

steps.solution:
interface ContactFormState {
  currentStep: number
  formData: {
    name: string
    email: string
    message: string
  }

  // Actions
  nextStep: () => void
  prevStep: () => void
  goToStep: (step: number) => void
  updateField: <K extends keyof ContactFormState['formData']>(
    field: K,
    value: ContactFormState['formData'][K]
  ) => void
  reset: () => void
}

import { create } from 'zustand'
import { persist } from 'zustand/middleware'

const initialState = {
  currentStep: 1,
  formData: { name: '', email: '', message: '' }
}

export const useContactStore = create<ContactFormState>()(
  persist(
    (set) => ({
      ...initialState,

      nextStep: () => set((state) => ({
        currentStep: Math.min(state.currentStep + 1, 5)
      })),

      prevStep: () => set((state) => ({
        currentStep: Math.max(state.currentStep - 1, 1)
      })),

      goToStep: (step) => set({ currentStep: step }),

      updateField: (field, value) => set((state) => ({
        formData: { ...state.formData, [field]: value }
      })),

      reset: () => set(initialState)
    }),
    { name: 'contact-form' }
  )
)
